const input = $input.first().json;

const sessionId = input.sessionId || input.chatId || 'chat-' + Date.now();
const messageText = input.chatInput || input.message || input.text || '';

return [{
  json: {
    userId: sessionId,
    userName: 'Chat User',
    messageText,
    mediaUrl: null,
    mediaType: 'text',
    channel: 'chat',
    sessionId,
    rawPayload: input
  }
}];

const entry = $input.first().json;
const value = entry.entry?.[0]?.changes?.[0]?.value || {};
const contacts = value.contacts || [];
const messages = value.messages || [];

if (!messages.length) return [];

const msg = messages[0];
const contact = contacts[0] || {};

let mediaUrl = null;
let mediaType = 'text';
let messageText = null;

if (msg.type === 'text') {
  messageText = msg.text?.body || '';
} else if (msg.type === 'image') {
  mediaType = 'image';
  mediaUrl = msg.image?.id || null;
  messageText = msg.image?.caption || '';
} else if (msg.type === 'document') {
  mediaType = 'pdf';
  mediaUrl = msg.document?.id || null;
  messageText = msg.document?.caption || '';
}

return [{
  json: {
    userId: contact.wa_id || msg.from || '',
    userName: contact.profile?.name || '',
    messageText,
    mediaUrl,
    mediaType,
    channel: 'whatsapp',
    rawPayload: entry
  }
}];

const update = $input.first().json;
const msg = update.message || {};
const chat = msg.chat || {};
const from = msg.from || {};

let mediaUrl = null;
let mediaType = 'text';
let messageText = msg.text || '';

if (msg.photo && msg.photo.length > 0) {
  mediaType = 'image';
  mediaUrl = msg.photo[msg.photo.length - 1].file_id;
  messageText = msg.caption || '';
} else if (msg.document) {
  const mime = msg.document.mime_type || '';
  mediaType = mime.includes('pdf') ? 'pdf' : 'image';
  mediaUrl = msg.document.file_id;
  messageText = msg.caption || '';
}

return [{
  json: {
    userId: String(chat.id || ''),
    userName: [from.first_name, from.last_name].filter(Boolean).join(' '),
    messageText,
    mediaUrl,
    mediaType,
    channel: 'telegram',
    rawPayload: update
  }
}];

const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    userId: body.userId || body.user_id || '',
    userName: body.userName || body.user_name || '',
    messageText: body.text || body.message || '',
    mediaUrl: body.mediaUrl || body.media_url || null,
    mediaType: body.mediaType || body.media_type || 'text',
    channel: 'webhook',
    rawPayload: body
  }
}];

const input = $input.first().json;
const lookupResults = $('Lookup User Profile').all() || [];
const normalized = $('Normalize Telegram').all().concat(
  // $('Normalize WhatsApp').all(),
