);
const msg = normalized.find(n => n.json.userId || n.json.id || n.json.profileId || n.json.chatId || n.json.phone) || { json: {} };

console.log('lookupResults:', JSON.stringify(lookupResults, null, 2));
console.log('normalized:', JSON.stringify(normalized, null, 2));
