const expenseData = $('Create Month Sheet If Needed').first().json;
const apiResponse = $input.first().json;
const rows = apiResponse.values || [];
const category = expenseData.category;
const amount = Number(expenseData.amount) || 0;

// rows[0] = header, rows[1..8] = category data
// Columns: A=Category, B=Budget, C=Spent This Month, D=Remaining
let rowNumber = -1;
let currentSpent = 0;
let budget = 0;

for (let i = 1; i < rows.length; i++) {
  if (rows[i][0] === category) {
    rowNumber = i + 1; // +1 for 1-indexed sheets
    budget = Number(rows[i][1]) || 0;
    currentSpent = Number(rows[i][2]) || 0;
    break;
  }
}

if (rowNumber === -1) rowNumber = 9; // default to last row (Lain-lain)

const newSpent = currentSpent + amount;
const remaining = budget - newSpent;

return [{
  json: {
    spreadsheetId: expenseData.spreadsheetId,
    channel: expenseData.channel,
    userId: expenseData.userId,
    profileName: expenseData.profileName,
    sessionId: expenseData.sessionId,
    category: category,
    dashboardRow: rowNumber,
    newSpent: newSpent,
    remaining: remaining,
    replyText: expenseData.replyText || `✅ Recorded: ${expenseData.description} ${amount.toLocaleString()} (${category})`
  }
}];

const apiResponse = $input.first().json;
const allRows = apiResponse.values || [];
const originalData = $('Route by Intent').first().json;
const category = originalData.category;

// allRows[0] = header, allRows[1..8] = data
// Columns: A=Category, B=Budget, C=Spent This Month, D=Remaining
let lines = ['📊 Budget Status:\n'];

for (let i = 1; i < allRows.length; i++) {
  const row = allRows[i];
  const cat = row[0] || '';
  if (category && cat !== category) continue;
  const budget = Number(row[1]) || 0;
  const spent = Number(row[2]) || 0;
  const remaining = budget - spent;
  const status = budget > 0 ? (remaining >= 0 ? '✅' : '⚠️') : '—';
  lines.push(`${status} ${cat}: Spent ${spent.toLocaleString()} / Budget ${budget.toLocaleString()} (Remaining: ${remaining.toLocaleString()})`);
}

return [{
  json: {
    ...originalData,
    replyText: lines.join('\n')
  }
}];

const data = $input.first().json;
const categories = ['Makanan & Minuman', 'Transportasi', 'Tagihan', 'Hiburan', 'Belanja', 'Kesehatan', 'Langganan', 'Lain-lain'];
const idx = categories.indexOf(data.category);
const budgetRow = idx >= 0 ? idx + 2 : 9; // row 2-9, default to Lain-lain (row 9)

return [{
  json: {
    ...data,
    budgetRow
  }
}];

const data = $input.first().json;
const originalData = $('Route by Intent').first().json;
return [{
  json: {
    ...originalData,
    replyText: `✅ Budget set: ${originalData.category} = ${originalData.currency || 'IDR'} ${Number(originalData.amount).toLocaleString()} per ${originalData.period || 'month'}`
  }
}];

const apiResponse = $input.first().json;
const allRows = apiResponse.values || [];
const originalData = $('Route by Intent').first().json;

// allRows[0] = header [Date, Description, Category, Amount, ...]
// allRows[1..n] = data rows
const byCategory = {};
let total = 0;
let txCount = 0;

for (let i = 1; i < allRows.length; i++) {
  const row = allRows[i];
  const cat = row[2] || 'Lain-lain'; // Column C = Category
  const amt = Number(row[3]) || 0;    // Column D = Amount
  byCategory[cat] = (byCategory[cat] || 0) + amt;
  total += amt;
  txCount++;
}

let lines = [`📊 Expense Report (${originalData.period || 'This Month'}):\n`];
const sorted = Object.entries(byCategory).sort((a, b) => b[1] - a[1]);

for (const [cat, amt] of sorted) {
  const pct = total > 0 ? ((amt / total) * 100).toFixed(1) : 0;
  lines.push(`• ${cat}: IDR ${amt.toLocaleString()} (${pct}%)`);
}

if (txCount === 0) {
  lines.push('No expenses recorded this period.');
}

lines.push(`\n💰 Total: IDR ${total.toLocaleString()}`);
lines.push(`📝 Transactions: ${txCount}`);

return [{
  json: {
    ...originalData,
    replyText: lines.join('\n')
  }
}];

const data = $input.first().json;
const splitWith = data.splitWith;
const totalAmount = Number(data.amount);
const shareAmount = Math.round(totalAmount / 2);

return [{
  json: {
    ...data,
    selfAmount: shareAmount,
    otherAmount: totalAmount - shareAmount,
    otherProfile: splitWith,
    replyText: `✅ Split recorded: ${data.description} IDR ${totalAmount.toLocaleString()}\n• Your share: IDR ${shareAmount.toLocaleString()}\n• ${splitWith}'s share: IDR ${(totalAmount - shareAmount).toLocaleString()}`
  }
}];

const data = $input.first().json;
const targetRows = $('Lookup Split Target Profile').all();
const target = targetRows.find(r => r.json.profileName === data.otherProfile);

if (!target) {
  return [{
    json: {
      ...data,
      replyText: `⚠️ Profile "${data.otherProfile}" not found. They need to register first.`
    }
  }];
}

const now = new Date();
const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const monthSheet = monthNames[now.getMonth()] + '-' + now.getFullYear();

return [
  {
    json: {
      spreadsheetId: data.spreadsheetId,
      channel: data.channel,
      userId: data.userId,
      profileName: data.profileName,
      sessionId: data.sessionId,
      monthSheet,
      Date: data.date,
      Description: data.description,
      Category: data.category,
      Amount: data.selfAmount,
      Currency: data.currency || 'IDR',
      'Split With': data.otherProfile,
      Recurring: '',
      Notes: 'Split: your share',
      replyText: data.replyText
    }
  },
  {
    json: {
      spreadsheetId: target.json.spreadsheetId,
      channel: data.channel,
      userId: data.userId,
      profileName: data.profileName,
      sessionId: data.sessionId,
      monthSheet,
      Date: data.date,
      Description: data.description,
      Category: data.category,
      Amount: data.otherAmount,
      Currency: data.currency || 'IDR',
      'Split With': data.profileName,
      Recurring: '',
      Notes: `Split: ${data.otherProfile}'s share`,
      replyText: data.replyText
    }
  }
];

